import{Visualiser}from"../primitives/Visualiser.js";class Peak extends Visualiser{onblamready(){super.onblamready(),this.function="getTimeData",this.writeInterval()}getAverage(){let sum=0;for(const band of this.data)sum+=band*band;return Math.sqrt(sum/this.data.length)}writeInterval(){this.style.setProperty(`--${this.name}-interval`,this.ms/1e3+"s")}translate(){this.style.setProperty(`--${this.name}-peak`,this.getAverage())}static get observedAttributes(){return["fps"]}attributeChangedCallback(name,oldVal){"fps"===name&&oldVal&&this.writeInterval()}}export{Peak};